/*********************
 * Validate Document Signed
 * 
 * by Telmo Chiri
 ********************/
let documentSignedValidation = {
    SUBMIT: "YES",
    MESSAGE: "",
    PRIMARY_SIGNER_SHOW: "NO",
    PRIMARY_SIGNER_MESSAGE: "",
    SECONDARY_SIGNER_SHOW: "NO",
    SECONDARY_SIGNER_MESSAGE: "",
};
//Check if Has the document been signed
if ( this.PE_PRIMARY_AUTHORIZATION != null ) {
    if (this.PE_PRIMARY_AUTHORIZATION.SIGNATURE == "NO") {
        documentSignedValidation.PRIMARY_SIGNER_SHOW = "YES";
        documentSignedValidation.PRIMARY_SIGNER_MESSAGE = "The user " + this.PE_PRIMARY_AUTHORIZATION.USER_NAME + " does not have a signature configured on the system, please contact with your system administrator.";
    }
} else {
    documentSignedValidation.PRIMARY_SIGNER_SHOW = "NO";
    documentSignedValidation.PRIMARY_SIGNER_MESSAGE = "";
}
if ( this.PE_SECONDARY_AUTHORIZATION != null ) {
    if (this.PE_SECONDARY_AUTHORIZATION.SIGNATURE == "NO") {
        documentSignedValidation.SECONDARY_SIGNER_SHOW = "YES";
        documentSignedValidation.SECONDARY_SIGNER_MESSAGE = "The user " + this.PE_SECONDARY_AUTHORIZATION.USER_NAME + " does not have a signature configured on the system, please contact with your system administrator.";
    }
} else {
    documentSignedValidation.SECONDARY_SIGNER_SHOW = "NO";
    documentSignedValidation.SECONDARY_SIGNER_MESSAGE = "";
}


if (documentSignedValidation.PRIMARY_SIGNER_SHOW == "YES" || documentSignedValidation.SECONDARY_SIGNER_SHOW == "YES") {
    documentSignedValidation.SUBMIT = "NO";
}

return documentSignedValidation;
/**
 * Valid Value
 *
 * @param string value
 * @return bool
 * 
 * by Telmo Chiri
 */
function validValue(value) {
    return (value !== null && value !== "" && value !== 0 && value !== [] && (typeof value !== "undefined"));
}
